#include<cstdio>
#include<cstdlib>
#include<ctime>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)

typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
const int N=5e4+10;LL ans,x[N],y[N];
inline LL Dis(const int &i,const int &j){return 1ll*(x[i]-x[j])*(x[i]-x[j])+1ll*(y[i]-y[j])*(y[i]-y[j]);}
int main()
{
	srand(19260817);
	int n=read();rep(1,n,i)x[i]=read(),y[i]=read();
	while(true)
	{
		int p=rand()%n+1,T=5;
		while(T--)
		{
			int idx=1;LL mxn(-1);
			rep(1,n,i)if(mxn<Dis(p,i)){mxn=Dis(p,i);idx=i;}
			p=idx;ans<mxn?ans=mxn:0ll;
		}
		if(1.0*clock()/CLOCKS_PER_SEC>0.295)
		{
			printf("%lld\n",ans);
			return 0;
		}
	}
}
